#include<bits/stdc++.h>
#define ll long long
using namespace std;
ll n,ans=0;
stack<pair<ll,ll> > s;int h;
int main(void){
	//freopen("xx.in","r",stdin);
	//freopen("xx.out","w",stdout);
	scanf("%lld",&n);
	for(int i=1;i<=n;++i){
		scanf("%lld",&h);
		pair<int,int> p;
		p.first=h,p.second=1;
		while(s.size()&&s.top().first<h){
			ans+=s.top().second;
			s.pop();
		}if(s.size()&&s.top().first==h)ans+=s.top().second,++s.top().second;
		else s.push(p);
		if(s.size()>1)++ans;
	}printf("%lld",ans);
	
	return false;
}
